        "t_10fdab1c": "Dal 1987",
        "t_5ceb7437": "Tradizione Siciliana",
        "t_045b658b": "Tradizione siciliana e passione per l'olio extravergine di oliva nelle terre di San Biagio Platani",
        "t_f2756a63": "Il Nostro Percorso",
        "t_f35bcdfa": "Dalla piccola azienda familiare di 3 ettari alla realtà di oggi con 11 ettari coltivati",
        "t_348ea5f7": "L'Inizio",
        "t_953e3731": "Nasce l'Azienda Agricola Olio di Valeria con soli 3 ettari di terreno, portando avanti una tradizione olivicola secolare nelle terre di San Biagio Platani.",
        "t_fcccb46d": "2000s",
        "t_5f584cb7": "Crescita e Certificazioni",
        "t_3f04aca5": "Espansione a 11 ettari e ottenimento delle certificazioni biologiche e vegane. Riconoscimento da parte di Slow Food per la qualità eccellente.",
        "t_867377e9": "Espansione Europea",
        "t_fc074330": "Inizio delle esportazioni in Europa, portando l'eccellenza siciliana nei mercati internazionali più esigenti.",
        "t_106dbe03": "Oggi",
        "t_355a3d10": "Eccellenza Riconosciuta",
        "t_5cfd0c72": "Parte del Distretto Rurale di Qualità dei Sicani, con una produzione limitata di circa 10.000+ litri annui destinata ai mercati gourmet.",
        "t_4cae6891": "Il Nostro Territorio",
        "t_28191788": "Situati in Contrada Serre, a 550 metri di altitudine e a soli 30 km dal mare, nella suggestiva Valle del Platani. Un microclima unico che dona al nostro olio caratteristiche organolettiche eccezionali.",
        "t_9465638d": "<span class=\"stat-number\">550m</span> <span class=\"stat-label\">Altitudine</span>",
        "t_c58729f4": "<span class=\"stat-number\">30km</span> <span class=\"stat-label\">Dal Mare</span>",
        "t_bb475f65": "<span class=\"stat-number\">11</span> <span class=\"stat-label\">Ettari</span>",
        "t_f72d5344": "<span class=\"stat-number\">10000L+</span> <span class=\"stat-label\">Produzione Annua</span>",
        "t_75953b18": "Valle del Platani",
        "t_146cc261": "Un paesaggio mozzafiato dove tradizione e natura si incontrano per creare l'olio perfetto",
        "t_bd721f2a": "Le Nostre Cultivar",
        "t_7cecfad8": "Tre varietà autoctone siciliane che si fondono in un blend unico per aroma, sapore e colore",
        "t_9aee1691": "Biancolilla",
        "t_61cc315f": "Cultivar tipica siciliana che conferisce al nostro olio note delicate e un profumo fruttato inconfondibile.",
        "t_d00ea7bb": "Nocellara",
        "t_06395f71": "Varietà robusta che dona struttura e corpo all'olio, con sentori erbacei e un retrogusto leggermente piccante.",
        "t_3d88950e": "San Benedetto",
        "t_e1adb034": "Cultivar pregiata che arricchisce il blend con note aromatiche complesse e un colore dorato intenso.",
        "t_9f3d947c": "Standard di Eccellenza",
        "t_0a12d510": "Ogni bottiglia rispecchia il nostro impegno per la qualità superiore",
        "t_86721e6d": "Acidità &lt; 0.35%",
        "t_d94462a1": "Acidità estremamente bassa che garantisce freschezza e purezza del prodotto",
        "t_92fcfbbe": "Estrazione &lt; 27°C",
        "t_d1616b7e": "Spremitura a freddo per preservare tutte le proprietà organolettiche",
        "t_8564e4c0": "Raccolta Immediata",
        "t_e05daf7d": "Olive spremute entro poche ore dalla raccolta manuale",
        "t_aa0c4b68": "Alti Polifenoli",
