        "t_628bec89": "<a class=\"active\" href=\"dovesiamo.html\">Dove Siamo</a>",
        "t_c6ee898a": "<a class=\"mobile-nav-link\" data-i18n=\"header.home\" href=\"index.html\">HOME</a>",
        "t_abfb23c7": "<nav class=\"breadcrumb-nav\"> <a href=\"index.html\">Home</a> <i class=\"fas fa-chevron-right\"></i> <span class=\"current\">Dove Siamo</span> </nav>",
        "t_57d5fb0a": "📍 La Nostra Sede",
        "t_41ac31b6": "Dove Siamo",
        "t_88c9269d": "Dove siamo: nel cuore della Valle del Platani, tra le colline dell'entroterra agrigentino",
        "t_6a170397": "🏠 La Nostra Casa",
        "t_bcfac891": "San Biagio Platani",
        "t_e00bdc87": "La sede della nostra Azienda Agricola è situata nel piccolo paesino di San Biagio Platani, nel cuore della meravigliosa Valle del Platani.",
        "t_44bd95e8": "<div class=\"location-icon\">📍</div> <span>Indirizzo</span>",
        "t_c12dd268": "<strong>L'Olio di Valeria</strong>",
        "t_56adf5a7": "Via Alcide De Gasperi, n° 4",
        "t_36eac1b7": "92020 San Biagio Platani (Agrigento)",
        "t_eb621203": "<strong>Coordinate GPS:</strong><br/> Lat: 37.506771 | Long: 13.525724<br/> 37°30'24.311″N 13°31'32.235″E",
        "t_e3506721": "🗺️ Esplora su Maps",
        "t_4b0271ba": "<div class=\"location-icon\">🚗</div> <span>Distanze dalle Città</span>",
        "t_78c21fad": "Le Città Vicine <div class=\"distance-row\"> <span class=\"city-name\">Agrigento</span> <span class=\"distance\">36,7 km</span> </div> <div class=\"distance-row\"> <span class=\"city-name\">Palermo</span> <span class=\"distance\">114,3 km</span> </div> <div class=\"distance-row\"> <span class=\"city-name\">Trapani</span> <span class=\"distance\">173,8 km</span> </div> <div class=\"distance-row\"> <span class=\"city-name\">Catania</span> <span class=\"distance\">193,2 km</span> </div> <div class=\"distance-row\"> <span class=\"city-name\">Messina</span> <span class=\"distance\">288,7 km</span> </div>",
        "t_4d961f84": "🛣️ Indicazioni",
        "t_50861a31": "Come Raggiungerci",
        "t_1b5bcf76": "Vi aspettiamo a San Biagio Platani. Ecco le indicazioni stradali dalle principali città siciliane.",
        "t_421e56b2": "<div class=\"direction-icon\">🚗</div> <span>Da Palermo</span>",
        "t_2b5a8dae": "Statale <strong>Palermo – Agrigento</strong>. Imboccare lo svincolo per <strong>Casteltermini</strong>, proseguire direzione <strong>San Biagio Platani</strong> per altri 17 km.",
        "t_abec2720": "<div class=\"direction-icon\">🚗</div> <span>Da Catania</span>",
        "t_fb66d404": "<strong>Caltanissetta – Agrigento</strong>. Imboccare l'uscita direzione <strong>Raffadali</strong> e proseguire per <strong>Santa Elisabetta</strong>, seguire le indicazioni per <strong>San Biagio Platani</strong>.",
        "t_1c519c2b": "<div class=\"direction-icon\">🚗</div> <span>Da Trapani</span>",
        "t_7b1ae462": "Lungo la <strong>SS115</strong> in direzione <strong>Agrigento-Siracusa</strong>, uscire a <strong>Siculiana</strong> e proseguire attraversando <strong>Raffadali</strong>. Seguire indicazioni per <strong>Santa Elisabetta</strong> e <strong>Sant'Angelo Muxaro</strong>, continuare per <strong>San Biagio Platani</strong>.",
        "t_8e5b4103": "✈️ In Aereo",
        "t_6a889d15": "Aeroporti in Sicilia",
        "t_c4f091a3": "Per raggiungerci in aereo, la Sicilia dispone di 4 aeroporti internazionali.",
        "t_91667673": "PMO",
        "t_63a1a455": "Aeroporto Internazionale Falcone e Borsellino di Palermo-Punta Raisi",
        "t_a9fd8f82": "CTA",
        "t_2e3f53d6": "Aeroporto Internazionale Vincenzo Bellini di Catania-Fontanarossa",
        "t_03859a04": "TPS",
        "t_c52eaeb1": "Aeroporto Vincenzo Florio di Trapani-Birgi",
        "t_e20bb369": "CIY",
        "t_09973689": "Aeroporto Pio la Torre di Comiso",
        "t_74751b9b": "🗺️ Mappa Interattiva",
        "t_6e42095c": "La Valle del Platani",
        "t_ec7eef05": "San Biagio Platani si trova nel cuore della Valle del Platani, una delle zone più suggestive dell'entroterra agrigentino, circondata da colline coltivate a ulivi secolari.",
        "t_df2b6d45": "🧭 Apri in Google Maps",
        "t_3037115e": "Olio Extravergine San Biagio Platani | L'Olio di Valeria - Agrigento Sicilia",
        "t_019cb5b8": "<nav class=\"breadcrumb-nav\"> <a href=\"index.html\">Home</a> <i class=\"fas fa-chevron-right\"></i> <span class=\"current\">FAQ</span> </nav>",
        "t_4be4d66a": "❓ Domande Frequenti",
        "t_1fe917b0": "FAQ",
        "t_87a5ac6c": "Le nostre FAQ rispondono alle domande più frequenti su prodotti, spedizioni e servizi",
        "t_5e6b2bdd": "Effettuate spedizioni internazionali? <i class=\"fas fa-chevron-down faq-icon\"></i>",
        "t_a5c65810": "Attualmente spediamo in tutta Italia e in alcuni paesi dell'Unione Europea. Per spedizioni internazionali al di fuori dell'UE, vi preghiamo di contattarci direttamente per verificare la disponibilità e i costi di spedizione.",
        "t_235ac756": "Quando riceverò il mio ordine? <i class=\"fas fa-chevron-down faq-icon\"></i>",
        "t_ee023670": "Gli ordini vengono elaborati entro 1-2 giorni lavorativi. La spedizione standard richiede 3-5 giorni lavorativi per l'Italia. Per spedizioni urgenti, offriamo anche il servizio espresso con consegna in 24-48 ore.",
        "t_8282ec45": "Ho sbagliato le merce danneggiata, cosa faccio? <i class=\"fas fa-chevron-down faq-icon\"></i>",
        "t_d2774f84": "In caso di merce danneggiata durante il trasporto, vi preghiamo di contattarci immediatamente con foto del danno. Provvederemo alla sostituzione gratuita del prodotto nel minor tempo possibile.",
        "t_38feac74": "Mi sono dimenticato un prodotto, come faccio ad aggiungerlo nell'ordine? <i class=\"fas fa-chevron-down faq-icon\"></i>",
        "t_58db0aea": "Se l'ordine non è ancora stato spedito, potete contattarci per aggiungere prodotti. Se è già stato spedito, sarà necessario effettuare un nuovo ordine separato.",
        "t_b0714a30": "Posso ordinare dei prodotti da spedire con la confezione regalo? <i class=\"fas fa-chevron-down faq-icon\"></i>",
        "t_783465ad": "Certamente! Offriamo confezioni regalo eleganti per tutti i nostri prodotti. Potete selezionare questa opzione durante il checkout e aggiungere anche un messaggio personalizzato.",
        "t_e4fecbd4": "Prodotti e Conservazione",
        "t_d89d616c": "L'olio d'oliva ha scadenza? <i class=\"fas fa-chevron-down faq-icon\"></i>",
        "t_2d02eb48": "Il nostro olio extravergine di oliva ha una durata di 18 mesi dalla data di produzione se conservato correttamente. La data di scadenza è sempre indicata sull'etichetta del prodotto.",
        "t_19acb9c4": "Qual è il metodo migliore per conservare l'olio? <i class=\"fas fa-chevron-down faq-icon\"></i>",
        "t_dd25bf12": "L'olio deve essere conservato in luogo fresco, asciutto e al riparo dalla luce diretta. La temperatura ideale è tra 14-18°C. Evitate di conservarlo vicino a fonti di calore o in frigorifero.",
        "t_32f65952": "Generale",
        "t_3614bb91": "È nato qualche cosa di sbagliato. Come faccio a contattarvi? <i class=\"fas fa-chevron-down faq-icon\"></i>",
        "t_773e7228": "Potete contattarci tramite email, telefono o attraverso i nostri canali social. Tutti i nostri contatti sono disponibili nella sezione \"Contatti\" del sito. Risponderemo nel minor tempo possibile.",
        "t_0c92b692": "FAQ - Domande Frequenti | l'Olio di Valeria - Olio Siciliano",
