        "t_10fdab1c": "Since 1987",
        "t_5ceb7437": "Sicilian tradition",
        "t_045b658b": "Sicilian tradition and passion for extra virgin olive oil in the lands of San Biagio Platani",
        "t_f2756a63": "Our Path",
        "t_f35bcdfa": "From the small family business of 3 hectares to today's reality with 11 hectares under cultivation",
        "t_348ea5f7": "The Beginning",
        "t_953e3731": "The Olio di Valeria farm was born with just 3 hectares of land, carrying on a centuries-old olive growing tradition in the lands of San Biagio Platani.",
        "t_fcccb46d": "2000s",
        "t_5f584cb7": "Growth and Certifications",
        "t_3f04aca5": "Expansion to 11 hectares and obtaining organic and vegan certifications. Recognition by Slow Food for excellent quality.",
        "t_867377e9": "European expansion",
        "t_fc074330": "Start of exports to Europe, bringing Sicilian excellence to the most demanding international markets.",
        "t_106dbe03": "Today",
        "t_355a3d10": "Recognized Excellence",
        "t_5cfd0c72": "Part of the Sicani Rural Quality District, with a limited production of approximately 10,000+ liters per year destined for gourmet markets.",
        "t_4cae6891": "Our Territory",
        "t_28191788": "Located in Contrada Serre, 550 meters above sea level and just 30 km from the sea, in the suggestive Platani Valley. A unique microclimate that gives our oil exceptional organoleptic characteristics.",
        "t_9465638d": "<span class=\"stat-number\">550m</span> <span class=\"stat-label\">Altitude</span>",
        "t_c58729f4": "<span class=\"stat-number\">30km</span> <span class=\"stat-label\">From the sea</span>",
        "t_bb475f65": "<span class=\"stat-number\">11</span> <span class=\"stat-label\">Hectares</span>",
        "t_f72d5344": "<span class=\"stat-number\">10000L+</span> <span class=\"stat-label\">Annual Production</span>",
        "t_75953b18": "Platani Valley",
        "t_146cc261": "A breathtaking landscape where tradition and nature meet to create the perfect oil",
        "t_bd721f2a": "Our Cultivars",
        "t_7cecfad8": "Three native Sicilian varieties that come together in a unique blend in terms of aroma, flavor and colour",
        "t_9aee1691": "Biancolilla",
        "t_61cc315f": "Typical Sicilian cultivar that gives our oil delicate notes and an unmistakable fruity aroma.",
        "t_d00ea7bb": "Nocellara",
        "t_06395f71": "Robust variety that gives structure and body to the oil, with herbaceous hints and a slightly spicy aftertaste.",
        "t_3d88950e": "Saint Benedict",
        "t_e1adb034": "Fine cultivar that enriches the blend with complex aromatic notes and an intense golden color.",
        "t_9f3d947c": "Standard of Excellence",
        "t_0a12d510": "Each bottle reflects our commitment to superior quality",
        "t_86721e6d": "Acidity &lt; 0.35%",
        "t_d94462a1": "Extremely low acidity which guarantees freshness and purity of the product",
        "t_92fcfbbe": "Extraction &lt; 27°C",
        "t_d1616b7e": "Cold pressing to preserve all the organoleptic properties",
        "t_8564e4c0": "Immediate collection",
        "t_e05daf7d": "Olives pressed within a few hours of manual harvesting",
        "t_aa0c4b68": "High Polyphenols",
