        "t_ee3bf90f": "Message *",
        "t_7e74ea52": "Tell us how we can help you...",
        "t_0101ed11": "<span id=\"submitText\"> <i class=\"fas fa-paper-plane\"></i> Send Message </span> <span id=\"loadingText\" style=\"display: none;\"> <i class=\"fas fa-spinner fa-spin\"></i> Sending... </span>",
        "t_bbbad716": "We are here for you",
        "t_87f54ad5": "As a Sicilian family, we believe in the value of authentic relationships. Whether you are an extra virgin olive oil enthusiast, a restaurateur looking for superior quality, or simply curious about our history, we are always happy to share our passion.",
        "t_c5523be4": "<strong>Do not hesitate to contact us</strong> - every conversation is an opportunity to introduce the authentic flavor of Sicily.",
        "t_ce8ae9da": "E-mail",
        "t_fb1a4014": "<a href=\"mailto:info@oliodivaleria.it\">info@oliodivaleria.it</a>",
        "t_75607cea": "We respond within 24 hours",
        "t_bdf77dc7": "Telephone",
        "t_335f1ec0": "Mon-Fri: 9:00-18:00",
