        "t_f562c1cf": "Saturday: 9:00 - 13:00",
        "t_613a1d97": "Sunday: Closed",
        "t_67304739": "Come and visit us",
        "t_bb6cf9a0": "Our company is located in the heart of Sicily, in the countryside of San Biagio Platani, in the province of Agrigento. Here, among golden hills and centuries-old olive groves, we produce our extra virgin olive oil following family traditions.",
        "t_8fefa26f": "<strong>Company visits:</strong> We organize guided tours to introduce you to our production process and taste our oils. Contact us to book your visit.",
        "t_45b6bd78": "<strong>Administrative Headquarters</strong> <span>Contrada Serre, 19 - San Biagio Platani (AG)</span>",
        "t_be256a1a": "<strong>Frantoio</strong> <span>Via Alcide De Gasperi, 4 - San Biagio Platani (AG)</span>",
        "t_3b4d3ac2": "<strong>How to reach us</strong> <span>60 km from Agrigento, easily reachable by car</span>",
        "t_f8d57dbc": "San Biagio Platani, Agrigento",
        "t_f25c79d8": "Follow us and stay updated",
        "t_42af4a60": "Join our community to discover recipes, advice on extra virgin olive oil and the latest news from our Sicilian company.",
