        "t_7eada641": "San Biagio Platani (AG)",
        "t_475fef54": "<nav class=\"breadcrumb-nav\"> <a href=\"index.html\">Home</a> <i class=\"fas fa-chevron-right\"></i> <span class=\"current\" data-i18n=\"header.Azienda\">The Farm</span> </nav>",
        "t_10fdab1c": "Seit 1987",
        "t_5ceb7437": "Sizilianische Tradition",
        "t_045b658b": "Sizilianische Tradition und Leidenschaft für natives Olivenöl extra in den Gebieten von San Biagio Platani",
        "t_f2756a63": "Unser Weg",
        "t_f35bcdfa": "Vom kleinen Familienbetrieb mit 3 Hektar zur heutigen Realität mit 11 Hektar Anbaufläche",
        "t_348ea5f7": "Der Anfang",
        "t_953e3731": "Unser Familienbesitz Olio di Valeria entstand mit nur 3 Hektar Land und führt eine jahrhundertealte Tradition des Olivenanbaus in den Gebieten von San Biagio Platani fort.",
        "t_fcccb46d": "2000er Jahre",
        "t_5f584cb7": "Wachstum und Zertifizierungen",
        "t_3f04aca5": "Erweiterung auf 11 Hektar und Erlangung der Bio- und Vegan-Zertifizierung. Anerkennung von Slow Food für hervorragende Qualität.",
        "t_867377e9": "Europäische Expansion",
        "t_fc074330": "Beginn des Exports nach Europa, um sizilianische Exzellenz auf die anspruchsvollsten internationalen Märkte zu bringen.",
        "t_106dbe03": "Heute",
        "t_355a3d10": "Anerkannte Exzellenz",
        "t_5cfd0c72": "Teil des Sicani Rural Quality District mit einer begrenzten Produktion von mehr als 10.000 Litern pro Jahr für Gourmetmärkte.",
        "t_4cae6891": "Unser Territorium",
        "t_28191788": "Das Hotel liegt in Contrada Serre, 550 Meter über dem Meeresspiegel und nur 30 km vom Meer entfernt, im eindrucksvollen Platani-Tal. Ein einzigartiges Mikroklima, das unserem Öl außergewöhnliche organoleptische Eigenschaften verleiht.",
        "t_9465638d": "<span class=\"stat-number\">550 m</span> <span class=\"stat-label\">Höhe</span>",
        "t_c58729f4": "<span class=\"stat-number\">30 km</span> <span class=\"stat-label\">Vom Meer</span>",
        "t_bb475f65": "<span class=\"stat-number\">11</span> <span class=\"stat-label\">Hektar</span>",
        "t_f72d5344": "<span class=\"stat-number\">10000L+</span> <span class=\"stat-label\">Jahresproduktion</span>",
        "t_75953b18": "Platani-Tal",
        "t_146cc261": "Eine atemberaubende Landschaft, in der Tradition und Natur zusammentreffen, um das perfekte Öl zu schaffen",
        "t_bd721f2a": "Unsere Sorten",
        "t_7cecfad8": "Drei einheimische sizilianische Sorten, die in Bezug auf Aroma, Geschmack und Farbe eine einzigartige Mischung ergeben",
        "t_9aee1691": "Biancolilla",
        "t_61cc315f": "Typische sizilianische Sorte, die unserem Öl zarte Noten und ein unverwechselbares fruchtiges Aroma verleiht.",
        "t_d00ea7bb": "Nocellara",
        "t_06395f71": "Robuste Sorte, die dem Öl Struktur und Körper verleiht, mit Kräuternoten und einem leicht würzigen Nachgeschmack.",
        "t_3d88950e": "Heiliger Benedikt",
        "t_e1adb034": "Feine Sorte, die die Mischung mit komplexen aromatischen Noten und einer intensiven goldenen Farbe bereichert.",
        "t_9f3d947c": "Exzellenzstandard",
        "t_0a12d510": "Jede Flasche spiegelt unser Engagement für höchste Qualität wider",
        "t_86721e6d": "Säure &lt; 0,35 %",
        "t_d94462a1": "Extrem niedriger Säuregehalt, der Frische und Reinheit des Produkts garantiert",
        "t_92fcfbbe": "Extraktion &lt; 27°C",
        "t_d1616b7e": "Kaltpressung zur Erhaltung aller organoleptischen Eigenschaften",
        "t_8564e4c0": "Sofortige Abholung",
        "t_e05daf7d": "Oliven werden innerhalb weniger Stunden nach der manuellen Ernte gepresst",
        "t_aa0c4b68": "Hohe Polyphenole",
        "t_6b4553ba": "Reich an natürlichen Antioxidantien für hervorragende gesundheitliche Vorteile",
        "t_a73e409f": "Wo Sie uns finden",
        "t_d67564a6": "Zwei Standorte, um unsere Produktion und unsere Kunden optimal zu bedienen",
        "t_5516f011": "Verwaltungssitz <p>Contrada Serre 19<br/>92020 San Biagio Platani (AG)<br/>Sizilien, Italien</p>",
        "t_e37b489a": "Abfüllanlage <p>Via Alcide De Gasperi 4<br/>92020 San Biagio Platani (AG)<br/>Sizilien, Italien</p>",
        "t_9bf62a95": "Telefon <p>+39 327 309 8513</p>",
        "t_fb65b914": "Email <p>info@oliodivaleria.it</p>",
        "t_23e3c44c": "Zertifizierungen <p>Bio-zertifiziert<br/>Vegan-Zertifizierung<br/>Slow Food<br/>CSQA-zertifizierte Rückverfolgbarkeit<br/>Rural District Sicani</p>",
        "t_c0e95901": "Sizilianische Tradition seit 1987. Extra natives Olivenöl höchster Qualität aus dem Land San Biagio Platani.",
