        "t_47ffb582": "Bestelldetails",
        "t_9662de65": "<span class=\"order-detail-label\">Bestellnummer:</span> <span class=\"order-detail-value\" id=\"orderId\">-</span>",
        "t_46e081de": "<span class=\"order-detail-label\">Betrag:</span> <span class=\"order-detail-value\" id=\"orderTotal\">-</span>",
