        "t_628bec89": "<a class=\"active\" href=\"dovesiamo.html\">Anfahrt</a>",
        "t_c6ee898a": "<a class=\"mobile-nav-link\" data-i18n=\"header.home\" href=\"index.html\">HOME</a>",
        "t_abfb23c7": "<nav class=\"breadcrumb-nav\"> <a href=\"index.html\">Home</a> <i class=\"fas fa-chevron-right\"></i> <span class=\"current\">Anfahrt</span> </nav>",
        "t_57d5fb0a": "📍 Unser Hauptsitz",
        "t_41ac31b6": "Anfahrt",
        "t_88c9269d": "Anfahrt: im Herzen des Platani-Tals, zwischen den Hügeln des Hinterlandes von Agrigent",
        "t_6a170397": "🏠 Unser Zuhause",
        "t_bcfac891": "San Biagio Platani",
        "t_e00bdc87": "Der Hauptsitz unserer Farm befindet sich im kleinen Dorf San Biagio Platani, im Herzen des wunderschönen Platani-Tals.",
        "t_44bd95e8": "<div class=\"location-icon\">📍</div> <span>Adresse</span>",
        "t_c12dd268": "<strong>Valeriaöl</strong>",
        "t_56adf5a7": "Via Alcide De Gasperi, Nr. 4",
        "t_36eac1b7": "92020 San Biagio Platani (Agrigent)",
        "t_eb621203": "<strong>GPS-Koordinaten:</strong><br/> Breitengrad: 37.506771 | Länge: 13.525724<br/> 37°30'24.311″N 13°31'32.235″E",
        "t_e3506721": "🗺️ Entdecken Sie auf Karten",
        "t_4b0271ba": "<div class=\"location-icon\">🚗</div> <span>Entfernungen von Städten</span>",
        "t_78c21fad": "Die nahegelegenen Städte <div class=\"distance-row\"> <span class=\"city-name\">Agrigento</span> <span class=\"distance\">36,7 km</span> </div> <div class=\"distance-row\"> <span class=\"city-name\">Palermo</span> <span class=\"distance\">114,3 km</span> </div> <div class=\"distance-row\"> <span class=\"city-name\">Trapani</span> <span class=\"distance\">173,8 km</span> </div> <div class=\"distance-row\"> <span class=\"city-name\">Catania</span> <span class=\"city-name\">193,2 km</span> </div> <div class=\"distance-row\"> <span class=\"city-name\">Messina</span> <span class=\"distance\">288,7 km</span> </div>",
        "t_4d961f84": "🛣️ Wegbeschreibung",
        "t_50861a31": "So erreichen Sie uns",
        "t_1b5bcf76": "Wir erwarten Sie in San Biagio Platani. Hier finden Sie die Wegbeschreibungen zu den wichtigsten sizilianischen Städten.",
        "t_421e56b2": "<div class=\"direction-icon\">🚗</div> <span>Von Palermo</span>",
        "t_2b5a8dae": "<strong>Staatsstraße Palermo – Agrigent</strong>. Nehmen Sie die Abzweigung nach <strong>Casteltermini</strong> und fahren Sie weitere 17 km in Richtung <strong>San Biagio Platani</strong>.",
        "t_abec2720": "<div class=\"direction-icon\">🚗</div> <span>Von Catania</span>",
        "t_fb66d404": "<strong>Caltanissetta – Agrigent</strong>. Nehmen Sie die Ausfahrt Richtung <strong>Raffadali</strong> und fahren Sie weiter in Richtung <strong>Santa Elisabetta</strong>, folgen Sie der Beschilderung nach <strong>San Biagio Platani</strong>.",
        "t_1c519c2b": "<div class=\"direction-icon\">🚗</div> <span>Von Trapani</span>",
        "t_7b1ae462": "Entlang der <strong>SS115</strong> in Richtung <strong>Agrigento-Siracusa</strong>, Ausfahrt <strong>Siculiana</strong> und weiter über <strong>Raffadali</strong>. Folgen Sie den Schildern nach <strong>Santa Elisabetta</strong> und <strong>Sant'Angelo Muxaro</strong>, weiter nach <strong>San Biagio Platani</strong>.",
        "t_8e5b4103": "✈️ Mit dem Flugzeug",
        "t_6a889d15": "Flughäfen in Sizilien",
        "t_c4f091a3": "Um uns mit dem Flugzeug zu erreichen, verfügt Sizilien über 4 internationale Flughäfen.",
        "t_91667673": "PMO",
        "t_63a1a455": "Internationaler Flughafen Falcone e Borsellino von Palermo-Punta Raisi",
        "t_a9fd8f82": "CTA",
        "t_2e3f53d6": "Internationaler Flughafen Vincenzo Bellini von Catania-Fontanarossa",
        "t_03859a04": "TPS",
        "t_c52eaeb1": "Flughafen Trapani-Birgi Vincenzo Florio",
        "t_e20bb369": "CIY",
        "t_09973689": "Flughafen Pio la Torre in Comiso",
        "t_74751b9b": "🗺️ Interaktive Karte",
        "t_6e42095c": "Das Platani-Tal",
        "t_ec7eef05": "San Biagio Platani liegt im Herzen des Platani-Tals, einer der eindrucksvollsten Gegenden des Hinterlandes von Agrigent, umgeben von Hügeln mit jahrhundertealten Olivenbäumen.",
        "t_df2b6d45": "🧭 In Google Maps öffnen",
        "t_3037115e": "Natives Olivenöl Extra San Biagio Platani | Valeriaöl - Agrigent, Sizilien",
        "t_019cb5b8": "<nav class=\"breadcrumb-nav\"> <a href=\"index.html\">Startseite</a> <i class=\"fas fa-chevron-right\"></i> <span class=\"current\">FAQ</span> </nav>",
        "t_4be4d66a": "❓ Häufig gestellte Fragen",
        "t_1fe917b0": "FAQ",
        "t_87a5ac6c": "Unsere FAQ beantworten die am häufigsten gestellten Fragen zu Produkten, Versand und Dienstleistungen",
        "t_5e6b2bdd": "Versenden Sie international? <i class=\"fas fa-chevron-down faq-icon\"></i>",
        "t_a5c65810": "Wir versenden derzeit in ganz Italien und einigen Ländern der Europäischen Union. Für internationale Sendungen außerhalb der EU kontaktieren Sie uns bitte direkt, um die Verfügbarkeit und Versandkosten zu prüfen.",
        "t_235ac756": "Wann erhalte ich meine Bestellung? <i class=\"fas fa-chevron-down faq-icon\"></i>",
        "t_ee023670": "Bestellungen werden innerhalb von 1-2 Werktagen bearbeitet. Der Standardversand nach Italien dauert 3-5 Werktage. Für eilige Sendungen bieten wir auch einen Express-Service mit Zustellung innerhalb von 24-48 Stunden an.",
        "t_8282ec45": "Ich habe die beschädigte Ware falsch erhalten, was kann ich tun? <i class=\"fas fa-chevron-down faq-icon\"></i>",
        "t_d2774f84": "Sollte die Ware während des Transports beschädigt werden, kontaktieren Sie uns bitte umgehend mit Fotos des Schadens. Wir werden das Produkt so schnell wie möglich kostenlos ersetzen.",
        "t_38feac74": "Ich habe ein Produkt vergessen, wie füge ich es zur Bestellung hinzu? <i class=\"fas fa-chevron-down faq-icon\"></i>",
        "t_58db0aea": "Wenn Ihre Bestellung noch nicht versandt wurde, können Sie uns kontaktieren, um Produkte hinzuzufügen. Wenn es bereits versendet wurde, müssen Sie eine neue, separate Bestellung aufgeben.",
        "t_b0714a30": "Kann ich Produkte bestellen, die mit der Geschenkbox verschickt werden? <i class=\"fas fa-chevron-down faq-icon\"></i>",
        "t_783465ad": "Sicherlich! Wir bieten für alle unsere Produkte eine elegante Geschenkverpackung an. Sie können diese Option beim Bezahlvorgang auswählen und auch eine personalisierte Nachricht hinzufügen.",
        "t_e4fecbd4": "Produkte und Konservierung",
        "t_d89d616c": "Hat Olivenöl ein Verfallsdatum? <i class=\"fas fa-chevron-down faq-icon\"></i>",
        "t_2d02eb48": "Unser natives Olivenöl extra ist bei richtiger Lagerung ab Herstellungsdatum 18 Monate haltbar. Das Verfallsdatum ist immer auf dem Produktetikett angegeben.",
        "t_19acb9c4": "Was ist die beste Methode zur Lagerung von Öl? <i class=\"fas fa-chevron-down faq-icon\"></i>",
        "t_dd25bf12": "Das Öl muss an einem kühlen, trockenen Ort und vor direktem Licht geschützt gelagert werden. Die ideale Temperatur liegt zwischen 14 und 18 °C. Vermeiden Sie die Lagerung in der Nähe von Wärmequellen oder im Kühlschrank.",
        "t_32f65952": "Allgemein",
        "t_3614bb91": "Etwas ist falsch passiert. Wie kann ich Sie kontaktieren? <i class=\"fas fa-chevron-down faq-icon\"></i>",
        "t_773e7228": "Sie können uns per E-Mail, Telefon oder unsere sozialen Kanäle kontaktieren. Alle unsere Kontakte finden Sie im Abschnitt „Kontakte“ der Website. Wir werden so schnell wie möglich antworten.",
        "t_0c92b692": "FAQ - Häufig gestellte Fragen | Valeriaöl – Sizilianisches Öl",
