        "t_7eada641": "San Biagio Platani (AG)",
        "t_475fef54": "<nav class=\"breadcrumb-nav\"> <a href=\"index.html\">Accueil</a> <i class=\"fas fa-chevron-right\"></i> <span class=\"current\" data-i18n=\"header.Azienda\">Le Domaine Familial</span> </nav>",
        "t_10fdab1c": "Depuis 1987",
        "t_5ceb7437": "tradition sicilienne",
        "t_045b658b": "Tradition sicilienne et passion pour l'huile d'olive extra vierge sur les terres de San Biagio Platani",
        "t_f2756a63": "Notre chemin",
        "t_f35bcdfa": "De la petite entreprise familiale de 3 hectares à la réalité d'aujourd'hui avec 11 hectares en culture",
        "t_348ea5f7": "Le début",
        "t_953e3731": "Le Domaine Familial Olio di Valeria est née avec seulement 3 hectares de terrain, perpétuant une tradition oléicole séculaire sur les terres de San Biagio Platani.",
        "t_fcccb46d": "années 2000",
        "t_5f584cb7": "Croissance et certifications",
        "t_3f04aca5": "Agrandissement à 11 hectares et obtention des certifications bio et vegan. Reconnaissance par Slow Food pour une excellente qualité.",
        "t_867377e9": "Expansion européenne",
        "t_fc074330": "Début des exportations vers l’Europe, apportant l’excellence sicilienne aux marchés internationaux les plus exigeants.",
        "t_106dbe03": "Aujourd'hui",
        "t_355a3d10": "Excellence reconnue",
        "t_5cfd0c72": "Fait partie du district rural de qualité de Sicani, avec une production limitée d'environ 10 000+ litres par an destinés aux marchés gastronomiques.",
        "t_4cae6891": "Notre territoire",
        "t_28191788": "Situé à Contrada Serre, à 550 mètres d'altitude et à seulement 30 km de la mer, dans la suggestive vallée de Platani. Un microclimat unique qui confère à notre huile des caractéristiques organoleptiques exceptionnelles.",
        "t_9465638d": "<span class=\"stat-number\">550 m</span> <span class=\"stat-label\">Altitude</span>",
        "t_c58729f4": "<span class=\"stat-number\">30km</span> <span class=\"stat-label\">De la mer</span>",
        "t_bb475f65": "<span class=\"stat-number\">11</span> <span class=\"stat-label\">Hectares</span>",
        "t_f72d5344": "<span class=\"stat-number\">10 000 L+</span> <span class=\"stat-label\">Production annuelle</span>",
        "t_75953b18": "Vallée de Platani",
        "t_146cc261": "Un paysage à couper le souffle où tradition et nature se rencontrent pour créer l'huile parfaite",
        "t_bd721f2a": "Nos cultivars",
        "t_7cecfad8": "Trois variétés indigènes siciliennes réunies dans un mélange unique en termes d'arôme, de saveur et de couleur",
        "t_9aee1691": "Biancolilla",
        "t_61cc315f": "Cultivar typique sicilien qui donne à notre huile des notes délicates et un arôme fruité incomparable.",
        "t_d00ea7bb": "Nocellara",
        "t_06395f71": "Variété robuste qui donne structure et corps à l'huile, avec des notes herbacées et un arrière-goût légèrement épicé.",
        "t_3d88950e": "Saint Benoît",
        "t_e1adb034": "Beau cultivar qui enrichit l'assemblage de notes aromatiques complexes et d'une couleur dorée intense.",
        "t_9f3d947c": "Norme d'excellence",
        "t_0a12d510": "Chaque bouteille reflète notre engagement envers une qualité supérieure",
        "t_86721e6d": "Acidité &lt; 0,35%",
        "t_d94462a1": "Acidité extrêmement faible qui garantit la fraîcheur et la pureté du produit",
        "t_92fcfbbe": "Extraction &lt; 27°C",
        "t_d1616b7e": "Pressage à froid pour conserver toutes les propriétés organoleptiques",
        "t_8564e4c0": "Encaissement immédiat",
        "t_e05daf7d": "Olives pressées quelques heures après la récolte manuelle",
        "t_aa0c4b68": "Polyphénols élevés",
        "t_6b4553ba": "Riche en antioxydants naturels pour des bienfaits supérieurs pour la santé",
