        "t_c101af42": "<a class=\"btn btn-primary\" href=\"checkout.html\"> <i class=\"fas fa-redo\"></i> Réessayer le paiement </a> <a class=\"btn btn-secondary\" href=\"shop.html\"> <i class=\"fas fa-shopping-bag\"></i> Retourner à la ÉPICERIE FINE </a> <a class=\"btn btn-secondary\" href=\"contatti.html\"> <i class=\"fas fa-headset\"></i> Contactez-nous </a>",
